INSERT INTO public.testimonials (name, role, text, rating, avatar) VALUES ('Arun Kumar', 'CMA US Candidate', 'FETS provided an excellent testing environment. The staff was professional and helpful. I felt completely at ease during my Prometric exam. Highly recommended!', 5, 'AK');
INSERT INTO public.testimonials (name, role, text, rating, avatar) VALUES ('Priya Menon', 'IELTS Test Taker', 'The facilities at FETS are world-class. Clean, comfortable, and equipped with the latest technology. My IELTS experience was smooth from start to finish.', 5, 'PM');
INSERT INTO public.testimonials (name, role, text, rating, avatar) VALUES ('Rahul Sharma', 'AWS Certified', 'Exceptional service! The booking process was seamless, and the support team was available whenever I needed help. Successfully completed my AWS certification here.', 5, 'RS');
INSERT INTO public.testimonials (name, role, text, rating, avatar) VALUES ('Fathima Zahra', 'CELPIP Candidate', 'Being able to check exam dates and book through FETS saved me so much time. The mock exam prepared me perfectly for the real CELPIP test. Got my target score!', 5, 'FZ');
INSERT INTO public.testimonials (name, role, text, rating, avatar) VALUES ('Dr. Vishnu Nair', 'MRCS Part A', 'The private testing booths are excellent. Zero distractions during my MRCS exam. The biometric verification process was quick and professional.', 5, 'VN');
INSERT INTO public.testimonials (name, role, text, rating, avatar) VALUES ('Sneha Thomas', 'ACCA Student', 'I registered for early notifications and got access to exam dates before anyone else. Booked my preferred slot easily. The whole experience was premium.', 5, 'ST');
INSERT INTO public.faq_data (q, a) VALUES ('What ID do I need to bring for my exam?', 'You''ll need a valid government-issued photo ID (passport, driver''s license, or Aadhar card) and your exam confirmation email. Some exams may have additional requirements - please check your exam provider''s guidelines.');
INSERT INTO public.faq_data (q, a) VALUES ('How early should I arrive before my exam?', 'We recommend arriving at least 30 minutes before your scheduled exam time. This allows time for check-in procedures, biometric verification, and familiarization with the testing environment.');
INSERT INTO public.faq_data (q, a) VALUES ('Can I reschedule or cancel my exam?', 'Yes, you can reschedule or cancel your exam according to your exam provider''s policy. Please note that cancellation and rescheduling fees may apply. Contact us or your exam provider at least 24-48 hours before your scheduled exam.');
INSERT INTO public.faq_data (q, a) VALUES ('What items are prohibited in the testing room?', 'Personal belongings such as mobile phones, smartwatches, bags, study materials, and electronic devices are not allowed in the testing room. We provide secure lockers for storing your belongings during the exam.');
INSERT INTO public.faq_data (q, a) VALUES ('When will I receive my exam results?', 'Result delivery time varies by exam provider. Some exams provide immediate unofficial results, while others may take several days to weeks. Check with your specific exam provider for exact timelines.');
INSERT INTO public.faq_data (q, a) VALUES ('Do you offer mock tests?', 'Yes! We offer mock test facilities for CMA US, CELPIP, IELTS, TOEFL, GRE, and more. Mock tests simulate the actual exam environment so you can practice under real conditions. Visit our Mock Exams section to book.');
INSERT INTO public.faq_data (q, a) VALUES ('How does the early access registration work?', 'When you register with FETS, you''ll receive exclusive early notifications when new exam dates become available, especially for CMA US and CELPIP. This gives you a head start to book your preferred dates and times before they fill up.');
INSERT INTO public.faq_data (q, a) VALUES ('What are the testing center locations?', 'We have two state-of-the-art centers: one in Calicut (West Nadakkavu, 4th Floor, Kadooli Tower) and one in Kochi (Edappally, 6th Floor, Manjooran Estate). Both centers are well-connected by public transport.');
