INSERT INTO public.centers (id, name, address, phone, email, hours, images, directions, map_url) VALUES ('kochi', 'Kochi Centre', '6th Floor, Manjooran Estate, Behind MRA Hotel, Bypass Junction, Edappally, Kochi, Kerala 682024', '0484 4541957', 'edu@fets.in', 'Mon - Sun : 8 AM - 6 PM', ARRAY['/images/facility/kochi-reception.jpg','/images/facility/kochi-testing-hall.jpg','/images/facility/lockers-closeup.jpg'], ARRAY['{"mode":"Train","detail":"Ernakulam Town (ERN) - 6 KM | Ernakulam Junction (ERS) - 8.7 KM"}'::jsonb,'{"mode":"Metro","detail":"Edapally Metro Station - 350 Meters"}'::jsonb,'{"mode":"Bus","detail":"Kaloor Bus Stand - 5 KM | Vytilla Hub - 8.4 KM"}'::jsonb,'{"mode":"Air","detail":"Cochin International Airport (COK) (Approx. 28 KM)"}'::jsonb], 'https://maps.google.com/?q=Manjooran+Estate+Edappally+Kochi') ON CONFLICT DO NOTHING;
